/*
# Expose specific endpoints (not all — /env and /beans contain secrets)
management.endpoints.web.exposure.include=health,info,metrics,loggers,prometheus,threaddump

# Show full health details (only to authenticated users — configure in SecurityConfig)
management.endpoint.health.show-details=when-authorized
management.endpoint.health.show-components=when-authorized

# Kubernetes probes — separate liveness and readiness
management.endpoint.health.group.liveness.include=livenessState
management.endpoint.health.group.readiness.include=readinessState,db,redis

# Info endpoint — shows in /actuator/info
management.info.env.enabled=true
info.app.name=devlearner-api
info.app.version=@project.version@
info.app.description=Backend API for DevLearner platform

# Separate port for actuator (not exposed to internet)
management.server.port=8081
*/

import org.springframework.boot.actuate.health.*;
import org.springframework.boot.actuate.info.InfoContributor;
import org.springframework.boot.actuate.info.Info;
import org.springframework.stereotype.Component;
import io.micrometer.core.instrument.*;
import org.springframework.web.client.RestTemplate;
import java.time.Duration;
import java.util.Map;

// ── Custom HealthIndicator — checks external payment API ─────────────
@Component
public class PaymentGatewayHealthIndicator implements HealthIndicator {

    private final RestTemplate restTemplate;

    public PaymentGatewayHealthIndicator(RestTemplate restTemplate) {
        this.restTemplate = restTemplate;
    }

    @Override
    public Health health() {
        try {
            // Ping the payment gateway's health endpoint
            var resp = restTemplate.getForEntity(
                "https://api.payment-gateway.com/health", String.class);

            if (resp.getStatusCode().is2xxSuccessful()) {
                return Health.up()
                    .withDetail("gateway", "payment-gateway.com")
                    .withDetail("status", resp.getStatusCode().value())
                    .build();
            } else {
                return Health.down()
                    .withDetail("gateway", "payment-gateway.com")
                    .withDetail("status", resp.getStatusCode().value())
                    .build();
            }
        } catch (Exception e) {
            return Health.down()
                .withDetail("gateway", "payment-gateway.com")
                .withDetail("error", e.getMessage())
                .withException(e)
                .build();
        }
    }
}
// Response when UP:
// GET /actuator/health
// {"status":"UP","components":{"db":{"status":"UP"},
//   "paymentGateway":{"status":"UP","details":{"gateway":"payment-gateway.com"}}}}

