// ── Micrometer Metrics ───────────────────────────────────────────────
@Component
class OrderMetrics {
    private final Counter orderCreated;
    private final Counter orderFailed;
    private final Timer   orderProcessingTime;

    public OrderMetrics(MeterRegistry registry) {
        // Counter: monotonically increasing count
        this.orderCreated = Counter.builder("orders.created")
            .description("Total orders successfully created")
            .tag("env", "prod")
            .register(registry);

        this.orderFailed = Counter.builder("orders.failed")
            .description("Total order creation failures")
            .register(registry);

        // Timer: measures duration + throughput
        this.orderProcessingTime = Timer.builder("order.processing.time")
            .description("Time to process an order end-to-end")
            .publishPercentiles(0.5, 0.95, 0.99)  // p50, p95, p99
            .publishPercentileHistogram()
            .sla(Duration.ofMillis(200), Duration.ofMillis(500), Duration.ofSeconds(1))
            .register(registry);
    }

    public void recordOrderCreated() { orderCreated.increment(); }
    public void recordOrderFailed()  { orderFailed.increment(); }

    public <T> T timeOrder(java.util.concurrent.Callable<T> task) throws Exception {
        return orderProcessingTime.recordCallable(task);
    }
}

