import io.micrometer.core.annotation.Timed;
import io.micrometer.core.instrument.*;
import org.springframework.web.bind.annotation.*;
import org.springframework.http.ResponseEntity;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

// ── @Timed annotation — auto-creates a Timer metric ──────────────────
// Requires TimedAspect bean in config (or use @EnableAspectJAutoProxy)
@RestController
@RequestMapping("/api/orders")
public class OrderController {
    private static final Logger log = LoggerFactory.getLogger(OrderController.class);

    private final MeterRegistry registry;
    private final Gauge         activeOrders;
    private int                 activeOrderCount = 0;

    public OrderController(MeterRegistry registry) {
        this.registry = registry;
        // Gauge: reports current value (not cumulative)
        this.activeOrders = Gauge.builder("orders.active",
                this, c -> c.activeOrderCount)
            .description("Number of orders currently being processed")
            .register(registry);
    }

    // @Timed creates: orders.create{exception="none",outcome="SUCCESS"} timer
    @Timed(value = "orders.create", description = "Order creation latency",
           percentiles = {0.5, 0.95, 0.99})
    @PostMapping
    public ResponseEntity<String> createOrder(@RequestBody String body) {
        activeOrderCount++;
        try {
            log.info("Creating order: {}", body);
            // simulate work
            Thread.sleep((long)(Math.random() * 100));
            registry.counter("orders.created", "status", "success").increment();
            return ResponseEntity.status(201).body("Order created");
        } catch (Exception e) {
            registry.counter("orders.created", "status", "error").increment();
            throw new RuntimeException(e);
        } finally {
            activeOrderCount--;
        }
    }

    // Custom metric with tags — queryable in Prometheus by tag
    @GetMapping("/{id}")
    public ResponseEntity<String> getOrder(@PathVariable Long id,
                                           @RequestHeader(required=false) String region) {
        Timer.Sample sample = Timer.start(registry);
        try {
            // ... fetch order ...
            String r = region != null ? region : "unknown";
            sample.stop(Timer.builder("orders.get.latency")
                .tag("region", r)
                .register(registry));
            return ResponseEntity.ok("Order " + id);
        } catch (Exception e) {
            sample.stop(Timer.builder("orders.get.latency")
                .tag("region", region != null ? region : "unknown")
                .tag("exception", e.getClass().getSimpleName())
                .register(registry));
            throw e;
        }
    }
}

// ── TimedAspect bean — required for @Timed to work ───────────────────
import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;
import io.micrometer.core.aop.TimedAspect;

@Configuration
class MetricsConfig {
    @Bean
    public TimedAspect timedAspect(MeterRegistry registry) {
        return new TimedAspect(registry);
    }
}

// ── Runtime log level change via Actuator ─────────────────────────────
// During an incident, enable DEBUG for one package without restart:
//
// POST /actuator/loggers/com.myapp.service
// Content-Type: application/json
// Body: {"configuredLevel": "DEBUG"}
//
// Check it:
// GET /actuator/loggers/com.myapp.service
// Response: {"configuredLevel":"DEBUG","effectiveLevel":"DEBUG"}
//
// Reset to INFO:
// POST /actuator/loggers/com.myapp.service
// Body: {"configuredLevel": null}
//
// Also useful: check all slow metrics at runtime:
// GET /actuator/metrics/orders.create
// Response includes: count, totalTime, max, percentile summaries

public class MetricsDemoMain {
    public static void main(String[] args) {
        System.out.println("Micrometer metric types:");
        System.out.println();
        System.out.println("Counter — monotonically increasing:");
        System.out.println("  registry.counter('requests.total', 'method', 'GET').increment()");
        System.out.println("  Use: total requests, errors, login attempts");
        System.out.println();
        System.out.println("Gauge — current snapshot value:");
        System.out.println("  Gauge.builder('queue.size', queue, Queue::size).register(registry)");
        System.out.println("  Use: active connections, queue depth, cache size");
        System.out.println();
        System.out.println("Timer — duration + throughput:");
        System.out.println("  Timer.builder('db.query').register(registry).record(() -> query())");
        System.out.println("  Use: HTTP latency, DB query time, external API call duration");
        System.out.println();
        System.out.println("DistributionSummary — value distribution:");
        System.out.println("  DistributionSummary.builder('request.size').register(reg).record(bytes)");
        System.out.println("  Use: request/response body sizes, batch sizes");
        System.out.println();
        System.out.println("Prometheus query examples:");
        System.out.println("  rate(orders_created_total[5m])          — orders/sec (5min window)");
        System.out.println("  orders_create_seconds{quantile='0.99'}  — p99 latency");
        System.out.println("  jvm_memory_used_bytes{area='heap'}       — heap usage");
        System.out.println("  hikaricp_connections_active              — DB pool active conns");
    }
}

problems.description:
Configure Spring Boot Actuator with custom metrics and security.

**application.yml:**
```yaml
management:
  endpoints:
    web:
      exposure:
        include: health,metrics,prometheus,info,loggers
  endpoint:
    health:
      show-details: when-authorized
  metrics:
    tags:
      application: ${spring.application.name}
```

**Custom metric:**
```java
@Service public class OrderService {
    private final Counter ordersCreated;
    public OrderService(MeterRegistry registry) {
        ordersCreated = Counter.builder("orders.created")
            .description("Total orders created")
            .tag("currency", "USD")
            .register(registry);
    }
    public Order create(OrderRequest req) {
        Order o = orderRepo.save(new Order(req));
        ordersCreated.increment();
        return o;
    }
}
```

**Key insight:** Micrometer is Spring Boot's metrics facade. `MeterRegistry` is injected automatically. Prometheus scrapes `/actuator/prometheus`. Tag by business dimension (currency, region) for slicing.

