import org.springframework.boot.actuate.health.*;
import org.springframework.beans.factory.annotation.Value;
import org.springframework.http.ResponseEntity;
import org.springframework.stereotype.Component;
import org.springframework.web.client.RestTemplate;

@Component("externalApi")  // component name becomes the key in /actuator/health response
public class Q2 implements HealthIndicator {

    @Value("${external.api.health-url:https://httpbin.org/status/200}")
    private String healthUrl;

    private final RestTemplate restTemplate;

    public Q2(RestTemplate restTemplate) {
        this.restTemplate = restTemplate;
    }

    @Override
    public Health health() {
        long start = System.currentTimeMillis();
        try {
            ResponseEntity<String> response =
                restTemplate.getForEntity(healthUrl, String.class);

            long responseTimeMs = System.currentTimeMillis() - start;

            if (response.getStatusCode().is2xxSuccessful()) {
                return Health.up()
                    .withDetail("url",            healthUrl)
                    .withDetail("responseTimeMs", responseTimeMs)
                    .withDetail("httpStatus",     response.getStatusCode().value())
                    .build();
            } else {
                return Health.down()
                    .withDetail("url",        healthUrl)
                    .withDetail("httpStatus", response.getStatusCode().value())
                    .withDetail("reason",     "Non-2xx response")
                    .build();
            }
        } catch (Exception e) {
            long responseTimeMs = System.currentTimeMillis() - start;
            return Health.down()
                .withDetail("url",            healthUrl)
                .withDetail("responseTimeMs", responseTimeMs)
                .withDetail("error",          e.getClass().getSimpleName())
                .withDetail("message",        e.getMessage())
                .build();
        }
    }

    public static void main(String[] args) {
        System.out.println("GET /actuator/health when UP:");
        System.out.println("{");
        System.out.println("  \"status\": \"UP\",");
        System.out.println("  \"components\": {");
        System.out.println("    \"db\": { \"status\": \"UP\" },");
        System.out.println("    \"externalApi\": {");
        System.out.println("      \"status\": \"UP\",");
        System.out.println("      \"details\": {");
        System.out.println("        \"url\": \"https://httpbin.org/status/200\",");
        System.out.println("        \"responseTimeMs\": 145,");
        System.out.println("        \"httpStatus\": 200");
        System.out.println("      }");
        System.out.println("    }");
        System.out.println("  }");
        System.out.println("}");
        System.out.println();
        System.out.println("GET /actuator/health when DOWN (API unreachable):");
        System.out.println("{");
        System.out.println("  \"status\": \"DOWN\",");
        System.out.println("  \"components\": {");
        System.out.println("    \"externalApi\": {");
        System.out.println("      \"status\": \"DOWN\",");
        System.out.println("      \"details\": {");
        System.out.println("        \"error\": \"ResourceAccessException\",");
        System.out.println("        \"message\": \"Connection timed out\",");
        System.out.println("        \"responseTimeMs\": 5003");
        System.out.println("      }");
        System.out.println("    }");
        System.out.println("  }");
        System.out.println("}");
        System.out.println();
        System.out.println("When externalApi is DOWN → aggregate status is DOWN");
        System.out.println("→ Kubernetes readiness probe fails (if in readiness group)");
        System.out.println("→ Load balancer removes pod from rotation");
    }
}
